import 'package:dartz/dartz.dart';
import '../../../core/errors/exceptions.dart';
import '../../../core/errors/failures.dart';
import '../../../core/network/network_info.dart';
import '../../domain/entities/${name}_entity.dart';
import '../../domain/repositories/${name}_repository.dart';
import '../datasources/${name}_local_datasource.dart';
import '../datasources/${name}_remote_datasource.dart';

class ${className}RepositoryImpl implements ${className}Repository {
  final ${className}RemoteDataSource remoteDataSource;
  final ${className}LocalDataSource localDataSource;
  final NetworkInfo networkInfo;

  ${className}RepositoryImpl({
    required this.remoteDataSource,
    required this.localDataSource,
    required this.networkInfo,
  });

  @override
  Future<Either<Failure, ${className}Entity>> get$className() async {
    if (await networkInfo.isConnected) {
      // Device is online — fetch from remote
      try {
        final remote = await remoteDataSource.get$className();

        // Cache the fresh data locally
        await localDataSource.cache$className(remote);

        return Right(remote);
      } on ServerException catch (e) {
        return Left(ServerFailure(message: e.message));
      } on AuthException catch (e) {
        return Left(AuthFailure(message: e.message));
      }
    } else {
      // Device is offline — return cached data
      try {
        final cached = await localDataSource.getCached$className();
        return Right(cached);
      } on CacheException catch (e) {
        return Left(CacheFailure(message: e.message));
      }
    }
  }

  // TODO: Implement other repository methods here
}
''';

