import '../../domain/entities/${name}_entity.dart';
import '../../domain/usecases/get_$name.dart';

part '${name}_event.dart';
part '${name}_state.dart';

class ${className}Bloc extends Bloc<${className}Event, ${className}State> {
  final Get${className}UseCase get$className;

  // TODO: Inject all use cases this BLoC depends on
  ${className}Bloc({
    required this.get$className,
    // TODO: Add more use cases
    // required this.create$className,
    // required this.delete$className,
  }) : super(const ${className}Initial()) {
    // Register event handlers
    on<Get${className}Event>(_onGet$className);

    // TODO: Register handlers for additional events
    // on<Update${className}Event>(_onUpdate$className);
    // on<Refresh${className}Event>(_onRefresh$className);
  }

  /// Handles [Get${className}Event] — fetches data and emits loading/loaded/error.
  Future<void> _onGet$className(
    Get${className}Event event,
    Emitter<${className}State> emit,
  ) async {
    emit(const ${className}Loading());

    final result = await get$className(NoParams());

    result.fold(
      // On failure — emit error with the failure message
      (failure) => emit(${className}Error(message: failure.message)),
      // On success — emit loaded with the entity
      (entity) => emit(${className}Loaded(entity: entity)),
    );
